{"code": "import json
import os

# Load the data from the query result file
file_path = var_functions.query_db:12

# Read the full data from the file
with open(file_path, 'r') as f:
    data = json.load(f)

# Group data by index and calculate up/down days
results = {}

for record in data:
    index = record['Index']
    if index not in results:
        results[index] = {'up_days': 0, 'down_days': 0, 'total_days': 0}

    # Convert string values to float for comparison
    try:
        open_price = float(record['Open'])
        close_price = float(record['Close'])

        if close_price > open_price:
            results[index]['up_days'] += 1
        elif close_price < open_price:
            results[index]['down_days'] += 1
            # If equal, it's neither up nor down, we don't count it

        results[index]['total_days'] += 1
    except (ValueError, TypeError):
        # Skip records with invalid data
        continue

# Find indices with more up days than down days
up_more_than_down = []
for index, stats in results.items():
    if stats['up_days'] > stats['down_days']:
        up_more_than_down.append({
            'index': index,
            'up_days': stats['up_days'],
            'down_days': stats['down_days'],
            'total_days': stats['total_days']
        })

# Sort by index name for consistent output
up_more_than_down.sort(key=lambda x: x['index'])

# Create output string with results
output = []
output.append("Analysis of North American stock indices in 2018:")
output.append("")

for idx in up_more_than_down:
    output.append(f"Index {idx['index']}: {idx['up_days']} up days, {idx['down_days']} down days (total: {idx['total_days']} days)")

if not up_more_than_down:
    output.append("No North American indices had more up days than down days in 2018.")
    final_answer = "None of the North American indices had more up days than down days in 2018."
else:
    indices_list = [idx['index'] for idx in up_more_than_down]
    final_answer = ", ".join(indices_list)

summary = "\n".join(output)
print("__RESULT__:")
print(json.dumps({
    'summary': summary,
    'indices_with_more_up_days': [idx['index'] for idx in up_more_than_down],
    'detailed_stats': up_more_than_down,
    'final_answer': final_answer
}))"}

